import{_ as n,o as a,c as l,a2 as o}from"./chunks/framework.B72_uj9U.js";const B=JSON.parse('{"title":"Provider Trait","description":"Designing the core provider trait that abstracts message sending, streaming, and token counting into a common interface that all LLM adapters implement.","frontmatter":{"title":"Provider Trait","description":"Designing the core provider trait that abstracts message sending, streaming, and token counting into a common interface that all LLM adapters implement."},"headers":[],"relativePath":"learn/project/13-multi-provider-support/02-provider-trait.md","filePath":"learn/project/13-multi-provider-support/02-provider-trait.md"}'),t={name:"learn/project/13-multi-provider-support/02-provider-trait.md"};function p(e,s,c,r,i,y){return a(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="provider-trait" tabindex="-1">Provider Trait <a class="header-anchor" href="#provider-trait" aria-label="Permalink to &quot;Provider Trait&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to design an async trait in Rust that captures the common operations across LLM providers</li><li>Which methods belong in the core trait versus provider-specific extensions</li><li>How to handle the differences in message formats, tool calling, and response structures at the trait boundary</li></ul></blockquote><p>The provider trait is the foundation of the entire multi-provider architecture. It defines the contract that every LLM adapter must satisfy, and it is the only interface your agentic loop interacts with. Getting this design right means the rest of the chapter flows naturally. Getting it wrong means you will be fighting the abstraction in every adapter.</p><p>Let&#39;s design the trait from the ground up, starting with the common types that all providers share, then building the trait itself.</p><h2 id="common-types-the-provider-neutral-vocabulary" tabindex="-1">Common Types: The Provider-Neutral Vocabulary <a class="header-anchor" href="#common-types-the-provider-neutral-vocabulary" aria-label="Permalink to &quot;Common Types: The Provider-Neutral Vocabulary&quot;">​</a></h2><p>Before you can define the trait, you need types that represent messages, responses, and tool calls without any provider-specific details. These types form the language that your agent core speaks.</p><p>Create <code>src/provider/types.rs</code>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> serde</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#F9E2AF;font-style:italic;">Deserialize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Serialize</span><span style="color:#9399B2;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// A role in the conversation.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Serialize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Deserialize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> PartialEq</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">serde</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">rename_all </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;lowercase&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> enum</span><span style="color:#F9E2AF;font-style:italic;"> Role</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    User</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Assistant</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    System</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// A single content block within a message.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Serialize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Deserialize</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">serde</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">tag </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;type&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> enum</span><span style="color:#F9E2AF;font-style:italic;"> ContentBlock</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">serde</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">rename </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;text&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Text</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> text</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> },</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">serde</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">rename </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolUse</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        name</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        input</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;"> serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Value</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">serde</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">rename </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;tool_result&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolResult</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        tool_use_id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        content</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        is_error</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> bool</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// A message in the conversation.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Serialize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Deserialize</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> Message</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> role</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Role</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> content</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ContentBlock</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// A tool definition the model can call.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Serialize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Deserialize</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> ToolDefinition</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> description</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> parameters</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;"> serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Value</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;"> // JSON Schema</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// Token usage for a single request.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Default</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> TokenUsage</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> input_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> output_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> cache_read_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">u32</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> cache_creation_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">u32</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// The complete response from a non-streaming request.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> ProviderResponse</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> content</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ContentBlock</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> usage</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> TokenUsage</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> model</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> stop_reason</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> StopReason</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// Why the model stopped generating.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> PartialEq</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> enum</span><span style="color:#F9E2AF;font-style:italic;"> StopReason</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    EndTurn</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolUse</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    MaxTokens</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    StopSequence</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Unknown</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Notice that these types borrow concepts from both Anthropic and OpenAI but are not specific to either. The <code>ContentBlock</code> enum uses a tagged union to represent text, tool calls, and tool results in a single type. The <code>ToolDefinition</code> uses a JSON Schema value for parameters, which both major providers accept.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you might use dataclasses or Pydantic models for these types:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#FAB387;font-style:italic;">@dataclass</span></span>
<span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> Message</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    role</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span></span>
<span class="line"><span style="color:#CDD6F4;">    content</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;font-style:italic;"> list</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">ContentBlock</span><span style="color:#9399B2;">]</span></span></code></pre></div><p>Python&#39;s duck typing means any dict with the right keys would work too. Rust&#39;s enums and structs give you compile-time guarantees that every message has a valid role and every content block is one of the known variants. You cannot accidentally create a <code>ContentBlock</code> with <code>type: &quot;unknown&quot;</code> -- the compiler rejects it.</p></div><h2 id="the-streaming-types" tabindex="-1">The Streaming Types <a class="header-anchor" href="#the-streaming-types" aria-label="Permalink to &quot;The Streaming Types&quot;">​</a></h2><p>Streaming requires its own set of types. Each provider sends chunks differently, but your agent needs a uniform stream of events:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">sync</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">mpsc</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// A single event from a streaming response.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> enum</span><span style="color:#F9E2AF;font-style:italic;"> StreamEvent</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// A chunk of text content.</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    TextDelta</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// The start of a tool use block.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolUseStart</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        name</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// A chunk of tool input JSON.</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    ToolInputDelta</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// The tool use block is complete.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolUseEnd</span><span style="color:#9399B2;">,</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Token usage information (typically sent at the end).</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Usage</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">TokenUsage</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// The stream is complete.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Done</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> stop_reason</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> StopReason</span><span style="color:#9399B2;"> },</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// An error occurred during streaming.</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Error</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// A handle to a streaming response.</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> StreamHandle</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> receiver</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;"> mpsc</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Receiver</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">StreamEvent</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The <code>StreamEvent</code> enum captures every meaningful event that can occur during streaming. Text arrives as deltas (chunks), tool calls arrive as a start event followed by input deltas and an end event, and usage arrives when the stream completes. This design lets the UI render incrementally without knowing which provider is generating the events.</p><h2 id="the-provider-trait" tabindex="-1">The Provider Trait <a class="header-anchor" href="#the-provider-trait" aria-label="Permalink to &quot;The Provider Trait&quot;">​</a></h2><p>Now for the trait itself. The key design decision is what belongs in the trait and what stays outside it.</p><p>In <code>src/provider/mod.rs</code>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> async_trait</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">async_trait</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#CBA6F7;"> crate</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">provider</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">types</span><span style="color:#94E2D5;">::*</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// The core provider trait that all LLM adapters implement.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">async_trait</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> trait</span><span style="color:#F9E2AF;font-style:italic;"> Provider</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Send</span><span style="color:#94E2D5;"> +</span><span style="color:#F9E2AF;font-style:italic;"> Sync</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Returns the provider&#39;s name (e.g., &quot;anthropic&quot;, &quot;openai&quot;, &quot;ollama&quot;).</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> name</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Returns the currently configured model identifier.</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> model</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Send a complete (non-streaming) request and wait for the full response.</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> send_message</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#94E2D5;">        &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">        system</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">        messages</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">Message</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;">        tools</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">ToolDefinition</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;">        max_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    )</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ProviderResponse</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> ProviderError</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Send a streaming request and return a handle to receive events.</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> stream_message</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#94E2D5;">        &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">        system</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">        messages</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">Message</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;">        tools</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">ToolDefinition</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#EBA0AC;">        max_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    )</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">StreamHandle</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> ProviderError</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The trait uses <code>async_trait</code> because both <code>send_message</code> and <code>stream_message</code> are async operations that involve network I/O. The <code>Send + Sync</code> bounds are required because the provider will be shared across async tasks.</p><p>Notice what is <em>not</em> in the trait:</p><ul><li><strong>Configuration and construction</strong>: Each provider has different configuration needs (API keys, base URLs, model-specific options). Construction happens outside the trait.</li><li><strong>Cost calculation</strong>: Pricing is provider-specific and changes frequently. It belongs in a separate cost tracking layer.</li><li><strong>Capability queries</strong>: Model capabilities are metadata about a provider, not operations the provider performs. They live in a separate capabilities system.</li></ul><p>This keeps the trait focused on the one thing all providers must do: send messages and receive responses.</p><h2 id="the-error-type" tabindex="-1">The Error Type <a class="header-anchor" href="#the-error-type" aria-label="Permalink to &quot;The Error Type&quot;">​</a></h2><p>Provider errors need to carry enough information for the fallback system to make routing decisions:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> thiserror</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Debug</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> enum</span><span style="color:#F9E2AF;font-style:italic;"> ProviderError</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">error</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;HTTP request failed: </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">0</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Http</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">from</span><span style="color:#9399B2;">]</span><span style="color:#F9E2AF;"> reqwest</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">error</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;API error (status </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">status</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">): </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">message</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Api</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        status</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u16</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        message</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        retryable</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> bool</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">error</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Rate limited, retry after </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">retry_after_ms:?</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">ms&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    RateLimited</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        retry_after_ms</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">u64</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">error</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Authentication failed: </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">0</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    AuthError</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">error</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Model not found: </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">0</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    ModelNotFound</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">error</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Request timed out after </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">timeout_ms</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">ms&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Timeout</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> timeout_ms</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u64</span><span style="color:#9399B2;"> },</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">error</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Stream error: </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">0</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    StreamError</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">error</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Serialization error: </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">0</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Serialization</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> ProviderError</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Returns true if the error is transient and the request could succeed on retry.</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> is_retryable</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> bool</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        match</span><span style="color:#F38BA8;"> self</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Http</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Api</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> retryable</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#94E2D5;"> *</span><span style="color:#CDD6F4;">retryable</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">RateLimited</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Timeout</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">StreamError</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">AuthError</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> false</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">ModelNotFound</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> false</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Serialization</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> false</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Returns true if the error suggests trying a different provider entirely.</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> should_fallback</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> bool</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        match</span><span style="color:#F38BA8;"> self</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">RateLimited</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Api</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> status</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#94E2D5;"> *</span><span style="color:#CDD6F4;">status </span><span style="color:#94E2D5;">&gt;=</span><span style="color:#FAB387;"> 500</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Timeout</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">AuthError</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">            _ </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#F38BA8;"> false</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The <code>is_retryable</code> and <code>should_fallback</code> methods are critical for the fallback chain system you will build in a later subchapter. They encode the knowledge about which failures are transient (worth retrying) and which suggest switching to a different provider entirely.</p><h2 id="using-the-trait-with-dynamic-dispatch" tabindex="-1">Using the Trait with Dynamic Dispatch <a class="header-anchor" href="#using-the-trait-with-dynamic-dispatch" aria-label="Permalink to &quot;Using the Trait with Dynamic Dispatch&quot;">​</a></h2><p>Your agentic loop will hold the provider as a trait object so it can work with any concrete implementation:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">sync</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Arc</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> Agent</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    provider</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Arc</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#F9E2AF;font-style:italic;"> Provider</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    system_prompt</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    tools</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ToolDefinition</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    messages</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Message</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> Agent</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> new</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">provider</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Arc</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#F9E2AF;font-style:italic;"> Provider</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> system_prompt</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F38BA8;"> Self</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Agent</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">            provider</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">            system_prompt</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">            tools</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(),</span></span>
<span class="line"><span style="color:#CDD6F4;">            messages</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(),</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> send</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ProviderResponse</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> ProviderError</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F38BA8;">        self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">provider</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">send_message</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#94E2D5;">            &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">system_prompt</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#94E2D5;">            &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">messages</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#94E2D5;">            &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">tools</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#FAB387;">            4096</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        )</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Using <code>Arc&lt;dyn Provider&gt;</code> gives you dynamic dispatch -- the concrete provider type is determined at runtime, and the agent does not need to be generic over the provider type. This simplifies the agent&#39;s type signature and makes it easy to swap providers at runtime (which you will do in the model switching subchapter).</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python&#39;s approach would look nearly identical:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> Agent</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89DCEB;font-style:italic;"> __init__</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> provider</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> LLMProvider</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> system_prompt</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">        self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">provider </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> provider</span></span></code></pre></div><p>The difference is that Python resolves the method call at runtime by looking up <code>send_message</code> in the object&#39;s attribute dictionary. Rust resolves it through a vtable -- a table of function pointers associated with the trait object. The performance is comparable, but Rust guarantees at compile time that the provider implements every required method.</p></div><h2 id="module-structure" tabindex="-1">Module Structure <a class="header-anchor" href="#module-structure" aria-label="Permalink to &quot;Module Structure&quot;">​</a></h2><p>Organize the provider code in a clean module hierarchy:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>  provider/</span></span>
<span class="line"><span>    mod.rs           # The Provider trait and ProviderError</span></span>
<span class="line"><span>    types.rs         # Message, ContentBlock, StreamEvent, etc.</span></span>
<span class="line"><span>    anthropic.rs     # Anthropic adapter</span></span>
<span class="line"><span>    openai.rs        # OpenAI adapter</span></span>
<span class="line"><span>    ollama.rs        # Ollama adapter</span></span>
<span class="line"><span>    capabilities.rs  # Model capability definitions</span></span>
<span class="line"><span>    fallback.rs      # Fallback chain logic</span></span>
<span class="line"><span>    cost.rs          # Cost tracking</span></span>
<span class="line"><span>    config.rs        # Provider configuration</span></span></code></pre></div><p>Each adapter file implements the <code>Provider</code> trait for its specific API. The <code>mod.rs</code> file re-exports the trait and common types so the rest of the codebase only needs <code>use crate::provider::*</code>.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>The provider trait defines two core operations: <code>send_message</code> for complete responses and <code>stream_message</code> for incremental streaming -- every LLM API supports both patterns</li><li>Provider-neutral types (<code>Message</code>, <code>ContentBlock</code>, <code>StreamEvent</code>) form the vocabulary that isolates your agent core from any specific API format</li><li>The error type carries classification metadata (<code>is_retryable</code>, <code>should_fallback</code>) that powers the fallback chain system</li><li>Dynamic dispatch with <code>Arc&lt;dyn Provider&gt;</code> lets the agent hold any provider implementation and swap it at runtime without changing the agent&#39;s type</li><li>Keep the trait minimal: configuration, cost calculation, and capability queries belong in separate systems, not in the core trait</li></ul>`,37)])])}const A=n(t,[["render",p]]);export{B as __pageData,A as default};
